import json
import sys

def validate_inputs(raw_leads_data, budget_threshold, source_criteria, timeout_duration):
    errors = []

    if not raw_leads_data:
        errors.append("原始线索数据不能为空")

    try:
        budget_val = float(budget_threshold)
        if budget_val <= 0:
            errors.append("预算分流阈值必须大于0")
    except:
        errors.append("预算分流阈值必须是有效数字")

    if not source_criteria or source_criteria.strip() == "":
        errors.append("来源分流标准不能为空")

    if timeout_duration:
        try:
            timeout_val = int(timeout_duration)
            if timeout_val <= 0:
                errors.append("超时时长必须大于0")
        except:
            errors.append("超时时长必须是有效整数")

    return {
        "is_valid": len(errors) == 0,
        "errors": errors,
        "budget_threshold": float(budget_threshold) if budget_threshold else 0,
        "source_criteria": source_criteria,
        "timeout_duration": int(timeout_duration) if timeout_duration else 72
    }

import pandas as pd
import json
import re

def clean_leads_data(raw_data):
    try:
        df = pd.read_json(raw_data)

        # 清理空值
        df = df.dropna(subset=['contact_info', 'source'])

        # 标准化联系方式
        if 'phone' in df.columns:
            df['phone'] = df['phone'].apply(lambda x: re.sub(r'[^0-9+]', '', str(x)) if pd.notnull(x) else '')

        if 'email' in df.columns:
            df['email'] = df['email'].apply(lambda x: str(x).lower().strip() if pd.notnull(x) else '')

        # 清理公司名称
        if 'company' in df.columns:
            df['company'] = df['company'].apply(lambda x: str(x).strip() if pd.notnull(x) else '')

        # 添加清理标记
        df['cleaned'] = True
        df['cleaning_timestamp'] = pd.Timestamp.now().isoformat()

        return {
            "success": True,
            "cleaned_data": df.to_dict(orient='records'),
            "original_count": len(raw_data),
            "cleaned_count": len(df),
            "removed_count": len(raw_data) - len(df)
        }
    except Exception as e:
        return {
            "success": False,
            "error": str(e),
            "cleaned_data": []
        }

import json
import datetime

def archive_low_value_leads(scored_leads, source_criteria):
    low_value_leads = []

    for lead in scored_leads:
        if lead['total_score'] < 40 or lead['score_level'] == 'low':
            archived_lead = {
                **lead,
                "archive_reason": "score_too_low",
                "archive_date": datetime.datetime.now().isoformat(),
                "source_criteria_applied": source_criteria
            }
            low_value_leads.append(archived_lead)

    return {
        "archived_leads": low_value_leads,
        "archive_count": len(low_value_leads),
        "archive_timestamp": datetime.datetime.now().isoformat()
    }

