import json

def format_final_output(aggregated_results, process_report):
    # 提取高价值线索（已分配）
    converted_opportunities = []
    if 'high_value_assignment' in aggregated_results and 'leads' in aggregated_results['high_value_assignment']:
        converted_opportunities = aggregated_results['high_value_assignment']['leads']

    # 提取低价值归档线索
    defeated_archives = []
    if 'low_value_archive' in aggregated_results and 'archived_leads' in aggregated_results['low_value_archive']:
        defeated_archives = aggregated_results['low_value_archive']['archived_leads']

    # 提取培育线索
    nurturing_leads = []
    if 'medium_value_assignment' in aggregated_results and 'leads' in aggregated_results['medium_value_assignment']:
        nurturing_leads = aggregated_results['medium_value_assignment']['leads']

    return {
        "converted_opportunities": converted_opportunities,
        "defeated_archives": defeated_archives,
        "nurturing_leads": nurturing_leads,
        "process_report": process_report['process_report'] if 'process_report' in process_report else {}
    }
